config.code:
function asObject(v) {
  return v && typeof v === 'object' && !Array.isArray(v) ? v : null;
}

function pickString(...values) {
  for (const value of values) {
    if (typeof value === 'string' && value.trim()) return value.trim();
  }
  return '';
}

const parsed = asObject(input.parsed) || {};
const pdf = asObject(input.pdf);
const chartData = asObject(parsed.chart_data) || { title: 'CSP distribution', labels: [], values: [] };
const artifactContext = asObject(parsed.artifact_context) || {};

const attachments = [];
if (pdf && typeof pdf.downloadUrl === 'string' && pdf.downloadUrl.trim()) {
  attachments.push({
    filename: pdf.filename || 'report.pdf',
    mimeType: pdf.mimeType || 'application/pdf',
    downloadUrl: pdf.downloadUrl,
    sizeBytes: typeof pdf.sizeBytes === 'number' ? pdf.sizeBytes : undefined
  });
}

return {
  answer: {
    status: pickString(parsed.status) || 'complete',
    final_html: pickString(parsed.final_html),
    python_code: pickString(parsed.python_code),
    follow_up_question: pickString(parsed.follow_up_question),
    chart_data: chartData,
    artifact_context: artifactContext,
    attachments
  }
};

